// Fire sub-workflow for each scene — 2 at a time, 10s between batches
// Avoids Fal.ai 429 rate limits
// Now uses 3-part cinematic prompt: composition_prefix + image_prompt + style_dna
const { execFileSync, execSync } = require('child_process');

const data = $input.first().json;
const scenes = data.scenes || [];
const topicId = data.topic_id;
const projectId = data.project_id;
const styleDna = data.style_dna || '';
const webhookUrl = 'http://localhost:5678/webhook/process-scene/image';
const token = $env.DASHBOARD_API_TOKEN;

// Universal negative prompt (prevents artifacts, text, style drift)
const NEGATIVE_PROMPT = 'text, watermark, signature, logo, UI elements, blurry, low quality, distorted faces, extra fingers, mutated hands, bad anatomy, deformed, disfigured, out of frame, cropped, duplicate, error, jpeg artifacts, low resolution, cartoon, anime, painting, illustration, 3D render, CGI';

const BATCH_SIZE = 2;
const BATCH_DELAY_SEC = 10;
let fired = 0;

for (let i = 0; i < scenes.length; i += BATCH_SIZE) {
  const batch = scenes.slice(i, i + BATCH_SIZE);

  for (const scene of batch) {
    // Build 3-part cinematic prompt
    const prefix = scene.composition_prefix || '';
    const subject = scene.image_prompt || '';
    const parts = [prefix, subject, styleDna].filter(Boolean);
    const fullPrompt = parts.join(' ');

    try {
      execFileSync('curl', [
        '-s', '-o', '/dev/null',
        '-X', 'POST', webhookUrl,
        '-H', 'Content-Type: application/json',
        '-H', 'Authorization: Bearer ' + token,
        '-d', JSON.stringify({
          scene_id: scene.id,
          image_prompt: fullPrompt,
          negative_prompt: NEGATIVE_PROMPT,
          topic_id: topicId,
          project_id: projectId
        }),
        '--connect-timeout', '3',
        '--max-time', '5'
      ]);
      fired++;
    } catch (e) { /* fire-and-forget */ }
  }

  // Wait between batches (skip wait after last batch)
  if (i + BATCH_SIZE < scenes.length) {
    execSync('sleep ' + BATCH_DELAY_SEC);
  }
}

return [{ json: { topic_id: topicId, project_id: projectId, fired, total: scenes.length, batch_size: BATCH_SIZE, delay_sec: BATCH_DELAY_SEC, has_style_dna: !!styleDna } }];

// Verify classification_status is reviewed before proceeding
const topic = $input.first().json;
// Handle array response from Supabase
const t = Array.isArray(topic) ? topic[0] : topic;
if (!t) {
  throw new Error('Topic not found. Check topic_id.');
}
if (t.classification_status !== 'reviewed') {
  throw new Error('Classification not reviewed. Run WF_SCENE_CLASSIFY first and accept results on dashboard.');
}
return [{ json: t }];

// Prepare Fal.ai scene data for sliding window processing + fetch style_dna
const scenes = $("Load Fal.ai Scenes").all().map(i => i.json);
const topicId = $("Webhook Trigger").item.json.body.topic_id;
const projectId = $("Check Classification").item.json.project_id;

// Flatten if Supabase returned array-in-item
let sceneList = scenes;
if (sceneList.length === 1 && Array.isArray(sceneList[0])) {
  sceneList = sceneList[0];
}

if (!Array.isArray(sceneList) || sceneList.length === 0 || (sceneList.length === 1 && !sceneList[0].id)) {
  return [{
    json: {
      scenes: [],
      topic_id: topicId,
      project_id: projectId,
      total_scenes: 0,
      scenes_completed: 0,
      scenes_failed: 0,
      total_image_cost: 0,
      skip_processing: true,
      style_dna: '',
    }
  }];
}

// Fetch project style_dna
let styleDna = '';
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${$env.SUPABASE_URL}/rest/v1/projects?id=eq.${projectId}&select=style_dna`,
    headers: {
      'apikey': $env.SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
    },
  });
  if (resp && resp[0] && resp[0].style_dna) {
    styleDna = resp[0].style_dna;
  }
} catch (e) {
  // style_dna is optional - continue without it
}

return [{
  json: {
    scenes: sceneList,
    topic_id: sceneList[0].topic_id || topicId,
    project_id: projectId,
    total_scenes: sceneList.length,
    scenes_completed: 0,
    scenes_failed: 0,
    total_image_cost: 0,
    skip_processing: false,
    style_dna: styleDna,
  }
}];

// Process Remotion scenes by calling local Remotion render service
// If no Remotion scenes, skip gracefully
const { execFileSync } = require("child_process");

const remotionScenes = $("Load Remotion Scenes").all().map(i => i.json);
const topicId = $("Webhook Trigger").item.json.body.topic_id;
const projectId = $("Check Classification").item.json.project_id;

// Flatten if Supabase returned array-in-item
let scenes = remotionScenes;
if (scenes.length === 1 && Array.isArray(scenes[0])) {
  scenes = scenes[0];
}

// If no Remotion scenes, skip
if (!scenes || scenes.length === 0 || (scenes.length === 1 && !scenes[0].id)) {
  return [{ json: { topic_id: topicId, project_id: projectId, remotion_results: [], total: 0, rendered: 0, skipped: true } }];
}

const results = [];
const hdr = ["-H", "apikey: " + $env.SUPABASE_ANON_KEY, "-H", "Authorization: Bearer " + $env.SUPABASE_SERVICE_ROLE_KEY];

for (const scene of scenes) {
  try {
    // Call local Remotion render service
    const renderPayload = JSON.stringify({
      template_key: scene.remotion_template || "default",
      data_payload: scene.data_payload || {},
      color_mood: scene.color_mood || "cool_neutral",
      format: "long",
      style_dna: scene.style_dna || "",
      output_path: "/tmp/renders/scene_" + String(scene.scene_number).padStart(3, "0") + ".png"
    });

    const response = execFileSync("curl", [
      "-s",
      "-X", "POST",
      "http://localhost:3100/render",
      "-H", "Content-Type: application/json",
      "-d", renderPayload,
      "--connect-timeout", "10",
      "--max-time", "120"
    ]).toString();

    const result = JSON.parse(response);

    if (result.success) {
      // Update scene in Supabase - mark as rendered
      execFileSync("curl", [
        "-s", "-X", "PATCH",
        $env.SUPABASE_URL + "/rest/v1/scenes?id=eq." + scene.id,
        ...hdr,
        "-H", "Content-Type: application/json",
        "-H", "Prefer: return=minimal",
        "-d", JSON.stringify({
          image_status: "rendered",
          image_url: result.file_path || result.output_path || ""
        })
      ]);
      results.push({ scene_number: scene.scene_number, status: "rendered" });
    } else {
      // Mark as failed in Supabase
      execFileSync("curl", [
        "-s", "-X", "PATCH",
        $env.SUPABASE_URL + "/rest/v1/scenes?id=eq." + scene.id,
        ...hdr,
        "-H", "Content-Type: application/json",
        "-H", "Prefer: return=minimal",
        "-d", JSON.stringify({ image_status: "failed" })
      ]);
      results.push({ scene_number: scene.scene_number, status: "failed", error: result.error || "Unknown render error" });
    }
  } catch (err) {
    // Mark as failed in Supabase
    try {
      execFileSync("curl", [
        "-s", "-X", "PATCH",
        $env.SUPABASE_URL + "/rest/v1/scenes?id=eq." + scene.id,
        ...hdr,
        "-H", "Content-Type: application/json",
        "-H", "Prefer: return=minimal",
        "-d", JSON.stringify({ image_status: "failed" })
      ]);
    } catch (e) { /* best effort */ }
    results.push({ scene_number: scene.scene_number, status: "failed", error: err.message });
  }
}

return [{ json: {
  topic_id: topicId,
  project_id: projectId,
  remotion_results: results,
  total: scenes.length,
  rendered: results.filter(r => r.status === "rendered").length,
  failed: results.filter(r => r.status === "failed").length,
  skipped: false
} }];

