// Parallel completion sync: check if ALL scenes (Fal.ai + Remotion) are done
// Fal.ai scenes: image_status = uploaded
// Remotion scenes: image_status = rendered
// After all complete, fires Ken Burns
const { execFileSync } = require("child_process");

const data = $input.first().json;
const topicId = data.topic_id || $("Webhook Trigger").item.json.body.topic_id;
const projectId = data.project_id || $("Webhook Trigger").item.json.body.project_id;
const hdr = ["-H", "apikey: " + $env.SUPABASE_ANON_KEY, "-H", "Authorization: Bearer " + $env.SUPABASE_SERVICE_ROLE_KEY];

const supaGet = (path) => JSON.parse(execFileSync("curl", ["-s", $env.SUPABASE_URL + '/rest/v1/' + path, ...hdr]).toString());

if (data.stopped) {
  return [{ json: { ...data, topic_id: topicId, project_id: projectId, assembly_claimed: false, reason: 'stopped' } }];
}

// Count completed scenes from both tracks
// Fal.ai completed = image_status=uploaded
const faiUploaded = supaGet('scenes?topic_id=eq.' + topicId + '&image_status=eq.uploaded&select=id');
// Remotion completed = image_status=rendered
const remotionRendered = supaGet('scenes?topic_id=eq.' + topicId + '&image_status=eq.rendered&select=id');
// Skipped
const skipped = supaGet('scenes?topic_id=eq.' + topicId + '&skipped=eq.true&select=id');

const completedCount = (Array.isArray(faiUploaded) ? faiUploaded.length : 0)
  + (Array.isArray(remotionRendered) ? remotionRendered.length : 0)
  + (Array.isArray(skipped) ? skipped.length : 0);

const totalScenes = supaGet('scenes?topic_id=eq.' + topicId + '&select=id');
const totalCount = Array.isArray(totalScenes) ? totalScenes.length : 0;

let assemblyClaimed = false;
if (completedCount >= totalCount && totalCount > 0) {
  // Update pipeline_stage to images (completed)
  execFileSync("curl", ["-s", "-X", "PATCH", $env.SUPABASE_URL + '/rest/v1/topics?id=eq.' + topicId, ...hdr, "-H", "Content-Type: application/json", "-H", "Prefer: return=minimal", "-d", JSON.stringify({ pipeline_stage: 'images', images_progress: 'complete' })]);
  assemblyClaimed = true; // Will trigger Ken Burns next
}

return [{ json: { ...data, topic_id: topicId, project_id: projectId, completed_visual_scenes: completedCount, total_visual_scenes: totalCount, assembly_claimed: assemblyClaimed } }];

